function workspaceDefaultSnapshot() {
  return {
    view: 'dashboard',
    selectedClientId: null,
    selectedCollaboratorId: null,
    clientTab: 'calendario',
    collaboratorTab: 'demandas',
    monthOffset: 0,
    collaboratorMonthOffset: 0,
    trafficMonthOffset: 0,
    trafficExpanded: {},
    blogExpanded: {},
    blogMonthRef: null,
    navigationHistory: [],
    filters: { search: '', status: '', client: '' }
  };
}

function getWorkspaceSnapshot() {
  return {
    view: state.view,
    selectedClientId: state.selectedClientId,
    selectedCollaboratorId: state.selectedCollaboratorId,
    clientTab: state.clientTab,
    collaboratorTab: state.collaboratorTab,
    monthOffset: Number(state.monthOffset || 0),
    collaboratorMonthOffset: Number(state.collaboratorMonthOffset || 0),
    trafficMonthOffset: Number(state.trafficMonthOffset || 0),
    trafficExpanded: { ...(state.trafficExpanded || {}) },
    blogExpanded: { ...(state.blogExpanded || {}) },
    blogMonthRef: state.blogMonthRef || null,
    navigationHistory: Array.isArray(state.navigationHistory)
      ? state.navigationHistory.map(item => ({ ...item }))
      : [],
    filters: { ...(state.filters || {}) }
  };
}

function applyWorkspaceSnapshot(snapshot = {}) {
  const base = workspaceDefaultSnapshot();
  const next = { ...base, ...snapshot };

  state.view = next.view;
  state.selectedClientId = next.selectedClientId;
  state.selectedCollaboratorId = next.selectedCollaboratorId;
  state.clientTab = next.clientTab;
  state.collaboratorTab = next.collaboratorTab;
  state.monthOffset = Number(next.monthOffset || 0);
  state.collaboratorMonthOffset = Number(next.collaboratorMonthOffset || 0);
  state.trafficMonthOffset = Number(next.trafficMonthOffset || 0);
  state.trafficExpanded = { ...(next.trafficExpanded || {}) };
  state.blogExpanded = { ...(next.blogExpanded || {}) };
  state.blogMonthRef = next.blogMonthRef || null;
  state.navigationHistory = Array.isArray(next.navigationHistory)
    ? next.navigationHistory.map(item => ({ ...item }))
    : [];
  state.filters = { ...(next.filters || base.filters) };
  state.modal = null;
}

function persistWorkspaceTabs() {
  save(STORAGE_KEYS.workspaceTabs, {
    activeWorkspaceId,
    tabs: workspaceTabs
  });
}

function initializeWorkspaceTabs() {
  const stored = load(STORAGE_KEYS.workspaceTabs, null);

  if (stored?.tabs?.length) {
    workspaceTabs = stored.tabs
      .filter(tab => tab?.id)
      .map(tab => ({
        id: String(tab.id),
        snapshot: { ...workspaceDefaultSnapshot(), ...(tab.snapshot || {}) }
      }));

    activeWorkspaceId = workspaceTabs.some(tab => tab.id === stored.activeWorkspaceId)
      ? stored.activeWorkspaceId
      : workspaceTabs[0].id;
  } else {
    const id = uid();
    workspaceTabs = [{
      id,
      snapshot: workspaceDefaultSnapshot()
    }];
    activeWorkspaceId = id;
  }

  const activeTab = workspaceTabs.find(tab => tab.id === activeWorkspaceId);
  applyWorkspaceSnapshot(activeTab?.snapshot || workspaceDefaultSnapshot());
  persistWorkspaceTabs();
}

function saveActiveWorkspaceState() {
  if (!activeWorkspaceId || !workspaceTabs.length) return;

  const index = workspaceTabs.findIndex(tab => tab.id === activeWorkspaceId);
  if (index === -1) return;

  workspaceTabs[index] = {
    ...workspaceTabs[index],
    snapshot: getWorkspaceSnapshot()
  };

  persistWorkspaceTabs();
}

function workspaceTabTitle(tab) {
  const snapshot = tab?.snapshot || {};
  const view = snapshot.view || 'dashboard';

  if (view === 'dashboard') return 'Dashboard';
  if (view === 'clientes') return 'Clientes';
  if (view === 'publicacoes') return 'Publicações';
  if (view === 'publicacoes-hoje') return 'Publicações do dia';
  if (view === 'colaboradores') return 'Colaboradores';
  if (view === 'trafego') return 'Tráfego pago';
  if (view === 'crm') return 'CRM de Prospecção';
  if (view === 'config') return 'Configurações';

  if (view === 'cliente') {
    const client = getClients().find(item =>
      String(item.registro_id || item.id || '') === String(snapshot.selectedClientId || '')
    );

    const labels = {
      calendario: 'Calendário',
      infos: 'Informações',
      publicacoes: 'Publicações',
      aprovacoes: 'Aprovação',
      blog: 'Blog',
      relatorios: 'Relatórios'
    };

    return `${labels[snapshot.clientTab] || 'Cliente'} ${client?.nome_cliente || ''}`.trim();
  }

  if (view === 'colaborador') {
    const collaborator = getCollaborators().find(item =>
      String(item.registro_id || item.id || '') === String(snapshot.selectedCollaboratorId || '')
    );

    return collaborator?.nome || 'Colaborador';
  }

  return 'Sistema LEME';
}

let draggedWorkspaceTabId = null;
let workspaceTabDropPosition = 'before';

function clearWorkspaceTabDropIndicators() {
  document
    .querySelectorAll('.workspace-tab.drop-before, .workspace-tab.drop-after, .workspace-tab.dragging')
    .forEach(element => {
      element.classList.remove('drop-before', 'drop-after', 'dragging');
    });
}

function dragWorkspaceTabStart(event, id) {
  draggedWorkspaceTabId = String(id || '');

  if (!draggedWorkspaceTabId) return;

  event.dataTransfer.effectAllowed = 'move';
  event.dataTransfer.setData('text/plain', draggedWorkspaceTabId);

  requestAnimationFrame(() => {
    event.currentTarget?.classList?.add('dragging');
  });
}

function dragWorkspaceTabOver(event, targetId) {
  event.preventDefault();

  const target = event.currentTarget;
  const normalizedTargetId = String(targetId || '');

  if (
    !draggedWorkspaceTabId ||
    !normalizedTargetId ||
    draggedWorkspaceTabId === normalizedTargetId
  ) {
    return;
  }

  document
    .querySelectorAll('.workspace-tab.drop-before, .workspace-tab.drop-after')
    .forEach(element => {
      if (element !== target) {
        element.classList.remove('drop-before', 'drop-after');
      }
    });

  const rect = target.getBoundingClientRect();
  workspaceTabDropPosition =
    event.clientX < rect.left + (rect.width / 2)
      ? 'before'
      : 'after';

  target.classList.toggle('drop-before', workspaceTabDropPosition === 'before');
  target.classList.toggle('drop-after', workspaceTabDropPosition === 'after');

  event.dataTransfer.dropEffect = 'move';
}

function dropWorkspaceTab(event, targetId) {
  event.preventDefault();
  event.stopPropagation();

  const draggedId = String(
    draggedWorkspaceTabId ||
    event.dataTransfer.getData('text/plain') ||
    ''
  );

  const normalizedTargetId = String(targetId || '');

  if (
    !draggedId ||
    !normalizedTargetId ||
    draggedId === normalizedTargetId
  ) {
    clearWorkspaceTabDropIndicators();
    draggedWorkspaceTabId = null;
    return;
  }

  const fromIndex = workspaceTabs.findIndex(tab =>
    String(tab.id) === draggedId
  );

  const originalTargetIndex = workspaceTabs.findIndex(tab =>
    String(tab.id) === normalizedTargetId
  );

  if (fromIndex === -1 || originalTargetIndex === -1) {
    clearWorkspaceTabDropIndicators();
    draggedWorkspaceTabId = null;
    return;
  }

  const [movedTab] = workspaceTabs.splice(fromIndex, 1);

  let targetIndex = workspaceTabs.findIndex(tab =>
    String(tab.id) === normalizedTargetId
  );

  if (targetIndex === -1) {
    workspaceTabs.push(movedTab);
  } else {
    if (workspaceTabDropPosition === 'after') {
      targetIndex += 1;
    }

    workspaceTabs.splice(targetIndex, 0, movedTab);
  }

  draggedWorkspaceTabId = null;
  workspaceTabDropPosition = 'before';

  clearWorkspaceTabDropIndicators();
  persistWorkspaceTabs();
  render({ skipAutoSync: true });
}

function dragWorkspaceTabEnd() {
  draggedWorkspaceTabId = null;
  workspaceTabDropPosition = 'before';
  clearWorkspaceTabDropIndicators();
  persistWorkspaceTabs();
}

function renderWorkspaceTabs() {
  return `
    <div class="workspace-tabs-bar">
      <div class="workspace-tabs-scroll">
        ${workspaceTabs.map(tab => `
          <div
            class="workspace-tab ${tab.id === activeWorkspaceId ? 'active' : ''}"
            draggable="true"
            ondragstart="dragWorkspaceTabStart(event, '${escapeAttr(tab.id)}')"
            ondragover="dragWorkspaceTabOver(event, '${escapeAttr(tab.id)}')"
            ondrop="dropWorkspaceTab(event, '${escapeAttr(tab.id)}')"
            ondragend="dragWorkspaceTabEnd()">

            <button
              type="button"
              class="workspace-tab-open"
              title="${escapeAttr(workspaceTabTitle(tab))}"
              onclick="switchWorkspaceTab('${escapeAttr(tab.id)}')">
              <span class="workspace-tab-icon">▣</span>
              <span class="workspace-tab-label">${escapeHtml(workspaceTabTitle(tab))}</span>
            </button>

            <button
              type="button"
              class="workspace-tab-close"
              title="Fechar janela"
              onclick="closeWorkspaceTab('${escapeAttr(tab.id)}', event)">×</button>
          </div>
        `).join('')}

        <button
          type="button"
          class="workspace-tab-add"
          title="Nova janela"
          onclick="createWorkspaceTab()">+</button>
      </div>
    </div>
  `;
}

function createWorkspaceTab() {
  saveActiveWorkspaceState();

  const id = uid();
  workspaceTabs.push({
    id,
    snapshot: workspaceDefaultSnapshot()
  });

  activeWorkspaceId = id;
  applyWorkspaceSnapshot(workspaceDefaultSnapshot());
  persistWorkspaceTabs();
  render({ skipAutoSync: true });
  syncAfterNavigation();
}

function switchWorkspaceTab(id) {
  if (String(id) === String(activeWorkspaceId)) return;

  saveActiveWorkspaceState();

  const tab = workspaceTabs.find(item => String(item.id) === String(id));
  if (!tab) return;

  activeWorkspaceId = tab.id;
  applyWorkspaceSnapshot(tab.snapshot);
  persistWorkspaceTabs();
  render({ skipAutoSync: true });
  syncAfterNavigation();
}

function closeWorkspaceTab(id, event) {
  event?.preventDefault?.();
  event?.stopPropagation?.();

  saveActiveWorkspaceState();

  const index = workspaceTabs.findIndex(item => String(item.id) === String(id));
  if (index === -1) return;

  const wasActive = String(activeWorkspaceId) === String(id);
  workspaceTabs.splice(index, 1);

  if (!workspaceTabs.length) {
    const newId = uid();
    workspaceTabs = [{
      id: newId,
      snapshot: workspaceDefaultSnapshot()
    }];
    activeWorkspaceId = newId;
  } else if (wasActive) {
    const nextTab = workspaceTabs[Math.max(0, index - 1)] || workspaceTabs[0];
    activeWorkspaceId = nextTab.id;
  }

  const activeTab = workspaceTabs.find(item => item.id === activeWorkspaceId);
  applyWorkspaceSnapshot(activeTab?.snapshot || workspaceDefaultSnapshot());
  persistWorkspaceTabs();
  render({ skipAutoSync: true });
  syncAfterNavigation();
}

let activeDrag = {
  type: null,
  id: null,
  sourceElement: null,
  dropped: false
};

function clearDragVisuals() {
  document.querySelectorAll('.is-dragging, .drop-target-active, .drop-target-hover')
    .forEach(el => el.classList.remove('is-dragging', 'drop-target-active', 'drop-target-hover'));

  if (activeDrag.sourceElement) {
    activeDrag.sourceElement.style.opacity = '';
    activeDrag.sourceElement.style.transform = '';
  }

  activeDrag = {
    type: null,
    id: null,
    sourceElement: null,
    dropped: false
  };
}

function createDragPreview(source, label = '') {
  if (!source) return null;

  const preview = source.cloneNode(true);
  preview.classList.add('drag-preview');
  preview.style.width = `${Math.max(source.offsetWidth, 220)}px`;
  preview.style.position = 'fixed';
  preview.style.top = '-1000px';
  preview.style.left = '-1000px';
  preview.style.pointerEvents = 'none';
  preview.style.zIndex = '99999';

  if (label) preview.setAttribute('aria-label', label);

  document.body.appendChild(preview);
  setTimeout(() => preview.remove(), 0);
  return preview;
}

function dragEnterTarget(event) {
  event.preventDefault();
  event.currentTarget?.classList?.add('drop-target-hover');
  if (event.dataTransfer) event.dataTransfer.dropEffect = 'move';
}

function dragLeaveTarget(event) {
  const target = event.currentTarget;
  if (!target) return;

  const next = event.relatedTarget;
  if (!next || !target.contains(next)) {
    target.classList.remove('drop-target-hover');
  }
}

function dragEndCleanup(event) {
  if (event?.currentTarget) {
    event.currentTarget.classList.remove('is-dragging');
  }
  setTimeout(clearDragVisuals, 40);
}


function load(key, fallback) {
  const raw = localStorage.getItem(key);
  if (!raw) return fallback;
  try { return JSON.parse(raw); } catch (e) { return fallback; }
}
function save(key, value) { localStorage.setItem(key, JSON.stringify(value)); }
function uid() { return crypto.randomUUID(); }

