function getClientBlogMonthKey(clientId, monthRef) {
  return `${clientId}__${monthRef}`;
}

function defaultBlogMonthRef() {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
}

function getBlogMonthLabel(monthRef) {
  const [year, month] = String(monthRef || '').split('-').map(Number);
  if (!year || !month) return monthRef || '';
  return `${MONTHS_PT[month - 1]} ${year}`;
}

