function fileToOptimizedBase64(file, maxWidth = 1200, maxHeight = 675, quality = 0.86) {
  return new Promise((resolve, reject) => {
    if (!file) return reject(new Error('Arquivo não encontrado.'));
    if (!file.type || !file.type.startsWith('image/')) return reject(new Error('Selecione uma imagem válida.'));
    if (file.size > 10 * 1024 * 1024) return reject(new Error('A imagem é muito pesada. Use uma imagem de até 10 MB.'));

    const reader = new FileReader();
    reader.onerror = () => reject(new Error('Não consegui ler a imagem.'));
    reader.onload = () => {
      const img = new Image();
      img.onerror = () => reject(new Error('Não consegui processar a imagem.'));
      img.onload = () => {
        let width = img.width;
        let height = img.height;
        const ratio = Math.min(maxWidth / width, maxHeight / height, 1);
        width = Math.round(width * ratio);
        height = Math.round(height * ratio);

        const canvas = document.createElement('canvas');
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, width, height);

        const mimeType = file.type === 'image/png' ? 'image/png' : 'image/jpeg';
        const base64 = canvas.toDataURL(mimeType, mimeType === 'image/jpeg' ? quality : undefined);
        resolve({
          imagem_nome: file.name,
          imagem_tipo: mimeType,
          imagem_base64: base64,
          imagem_tamanho: Math.round((base64.length * 3) / 4),
          imagem_largura: width,
          imagem_altura: height
        });
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}

async function handleBlogImageUpload(clientId, monthRef, articleId, input) {
  try {
    const file = input?.files?.[0];
    if (!file) return;
    const imageData = await fileToOptimizedBase64(file);
    saveBlogDraftField(clientId, monthRef, articleId, 'imagem_nome', imageData.imagem_nome);
    saveBlogDraftField(clientId, monthRef, articleId, 'imagem_tipo', imageData.imagem_tipo);
    saveBlogDraftField(clientId, monthRef, articleId, 'imagem_base64', imageData.imagem_base64);
    saveBlogDraftField(clientId, monthRef, articleId, 'imagem_tamanho', imageData.imagem_tamanho);
    saveBlogDraftField(clientId, monthRef, articleId, 'imagem_largura', imageData.imagem_largura);
    saveBlogDraftField(clientId, monthRef, articleId, 'imagem_altura', imageData.imagem_altura);
    render({ skipAutoSync: true });
    toast(`Imagem do artigo ${articleId} adicionada.`);
  } catch (error) {
    console.error(error);
    toast(error.message || 'Não consegui carregar a imagem.');
  } finally {
    if (input) input.value = '';
  }
}

