function getSettings() {
  const fallback = {
    ...DEFAULT_N8N_WEBHOOKS,
    lastAutoSyncAt: '',
    theme: 'light'
  };

  const current = load(STORAGE_KEYS.settings, {});
  const merged = {
    ...fallback,
    ...current
  };

  // Se o navegador já tinha configurações locais vazias, usa os webhooks padrão.
  Object.entries(DEFAULT_N8N_WEBHOOKS).forEach(([key, value]) => {
    if ((merged[key] === '' || merged[key] === undefined || merged[key] === null) && value) {
      merged[key] = value;
    }

    // Na versão PostgreSQL, o navegador deve falar com o backend próprio.
    // Se sobrou URL antiga do n8n no localStorage, ela é trocada pela rota local.
    if (typeof merged[key] === 'string' && value && value.startsWith('/webhook/') && /^https?:\/\//i.test(merged[key])) {
      merged[key] = value;
    }
  });

  if (!merged.apiMode || merged.apiMode === 'local') {
    merged.apiMode = 'webhook';
  }

  if (merged.autoSyncN8n !== false) {
    merged.autoSyncN8n = true;
  }

  return merged;
}
function setSettings(data) { save(STORAGE_KEYS.settings, data); }


