function renderClients() {
  const collaborators = [...getCollaborators()];
  const clients = [...getClients()];

  const collaboratorGroups = collaborators.map(collaborator => {
    const collaboratorId = String(
      collaborator.registro_id ||
      collaborator.id ||
      ''
    );

    const assignedClients = clients
      .filter(client =>
        String(client.responsavel_id || '') === collaboratorId
      )
      .sort((a, b) =>
        String(a.nome_cliente || '')
          .localeCompare(String(b.nome_cliente || ''), 'pt-BR')
      );

    return {
      collaborator,
      collaboratorId,
      clients: assignedClients
    };
  });

  const knownCollaboratorIds = new Set(
    collaboratorGroups.map(group => group.collaboratorId)
  );

  const unassignedClients = clients
    .filter(client =>
      !client.responsavel_id ||
      !knownCollaboratorIds.has(String(client.responsavel_id))
    )
    .sort((a, b) =>
      String(a.nome_cliente || '')
        .localeCompare(String(b.nome_cliente || ''), 'pt-BR')
    );

  if (unassignedClients.length) {
    collaboratorGroups.push({
      collaborator: {
        nome: 'Sem responsável',
        cargo: 'Clientes ainda não vinculados'
      },
      collaboratorId: 'sem-responsavel',
      clients: unassignedClients
    });
  }

  return `
    <section class="topbar clients-base-topbar">
      <div>
        <p class="eyebrow">Clientes</p>
        <h1>Base de clientes</h1>
        <p class="clients-base-description">
          Os clientes estão separados pelo colaborador responsável.
        </p>
      </div>

      <button class="btn" onclick="openClientModal()">Novo cliente</button>
    </section>

    ${collaboratorGroups.length ? `
      <section class="clients-by-collaborator-grid">
        ${collaboratorGroups.map(group =>
          renderCollaboratorClientColumn(
            group.collaborator,
            group.clients
          )
        ).join('')}
      </section>
    ` : `
      <div class="empty">Nenhum colaborador ou cliente cadastrado.</div>
    `}
  `;
}

