function buildGoogleDriveFolderUrl(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';

  if (/^https?:\/\//i.test(raw)) {
    return raw;
  }

  const cleanId = raw
    .replace(/^.*\/folders\//i, '')
    .replace(/[?#].*$/, '')
    .replace(/^\/+|\/+$/g, '');

  if (!cleanId) return '';

  return `https://drive.google.com/drive/folders/${cleanId}`;
}

function getClientDriveFolderUrl(client) {
  return buildGoogleDriveFolderUrl(
    client?.drive_folder_id ||
    client?.banco_google ||
    client?.drive_folder_url ||
    client?.pasta_drive ||
    ''
  );
}

function postFormatClass(format) {
  const normalized = String(format || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase();

  if (normalized === 'post unico') return 'format-post-unico';
  if (normalized === 'carrossel') return 'format-carrossel';
  if (normalized === 'reels') return 'format-reels';
  if (normalized === 'stories') return 'format-stories';

  return 'format-outro';
}

function getNextApprovalWeekRange() {
  const today = getSaoPauloNow();
  const currentDay = today.getDay();
  const daysUntilSunday = currentDay === 0 ? 7 : 7 - currentDay;
  const start = addDays(today, daysUntilSunday);
  const end = addDays(start, 6);

  return {
    start: formatDate(start),
    end: formatDate(end)
  };
}

