async function sendSingleBlogArticleToN8n(clientId, articleId) {
  const client = getClients().find(c => c.id === clientId);
  if (!client) return toast('Cliente não encontrado.');

  const monthRef = defaultBlogMonthRef();
  const article = getBlogArticleDraft(clientId, monthRef, articleId);

  if (!article.texto && !article.imagem_base64) {
    return toast(`Preencha o artigo ${articleId} antes de enviar.`);
  }

  const payload = {
    action: 'send_blog_article',
    source: 'sistema_leme',
    triggered_at: new Date().toISOString(),
    client: {
      id: client.id,
      registro_id: client.registro_id || client.id,
      nome_cliente: client.nome_cliente,
      site: client.site || client.dominio || '',
      dominio: client.dominio || client.site || '',
      slug_ebook: client.slug_ebook || '',
      drive_folder_url: getClientDriveFolderUrl(client)
    },
    mes_referencia: monthRef,
    mes_label: getBlogMonthLabel(monthRef),
    article: buildBlogArticlePayload(client, monthRef, article)
  };

  const res = await maybeWebhook('sendBlogArticles', payload);
  if (res?.ok === false) return toast('Não consegui enviar para o n8n. Confira o webhook de Blog nas configurações.');

  saveBlogDraftField(clientId, monthRef, articleId, 'enviado_em', new Date().toISOString());
  toast(`Artigo ${articleId} enviado para o n8n.`);
}

async function sendAllFilledBlogArticlesToN8n(clientId) {
  const client = getClients().find(c => c.id === clientId);
  if (!client) return toast('Cliente não encontrado.');

  const monthRef = defaultBlogMonthRef();
  const draft = getBlogDraft(clientId, monthRef);
  const articles = [1,2,3,4].map(id => getBlogArticleDraft(clientId, monthRef, id));
  const filledArticles = articles.filter(article => article.texto || article.imagem_base64);

  if (!filledArticles.length) return toast('Preencha pelo menos um artigo antes de enviar.');

  const payload = {
    action: 'send_blog_articles',
    source: 'sistema_leme',
    triggered_at: new Date().toISOString(),
    client: {
      id: client.id,
      registro_id: client.registro_id || client.id,
      nome_cliente: client.nome_cliente,
      site: client.site || client.dominio || '',
      dominio: client.dominio || client.site || '',
      slug_ebook: client.slug_ebook || '',
      drive_folder_url: getClientDriveFolderUrl(client)
    },
    mes_referencia: monthRef,
    mes_label: getBlogMonthLabel(monthRef),
    total_artigos_preenchidos: filledArticles.length,
    articles: filledArticles.map(article => buildBlogArticlePayload(client, monthRef, article))
  };

  const res = await maybeWebhook('sendBlogArticles', payload);
  if (res?.ok === false) return toast('Não consegui enviar para o n8n. Confira o webhook de Blog nas configurações.');

  draft.sent_at = new Date().toISOString();
  const drafts = getBlogDrafts();
  drafts[getClientBlogMonthKey(clientId, monthRef)] = draft;
  setBlogDrafts(drafts);

  toast(`${filledArticles.length} artigo(s) de ${getBlogMonthLabel(monthRef)} enviados para o n8n.`);
}


