function handleReportFilesChange(input) {
  const feedback = document.getElementById('report_files_feedback');
  const files = Array.from(input?.files || []);
  if (!feedback) return;
  if (!files.length) {
    feedback.textContent = 'Nenhum arquivo selecionado ainda.';
    return;
  }
  feedback.textContent = `${files.length} arquivo(s) selecionado(s): ${files.map(file => file.name).join(', ')}`;
}

function handleReportDragOver(event) {
  event.preventDefault();
  event.stopPropagation();
  event.currentTarget?.classList?.add('dragging');
}

function handleReportDragLeave(event) {
  event.preventDefault();
  event.stopPropagation();
  event.currentTarget?.classList?.remove('dragging');
}

function handleReportDrop(event) {
  event.preventDefault();
  event.stopPropagation();

  const uploader = event.currentTarget;
  uploader?.classList?.remove('dragging');

  const input = document.getElementById('report_files');
  const files = event.dataTransfer?.files;
  if (!input || !files || !files.length) return toast('Arraste arquivos CSV para gerar o relatório.');

  const dt = new DataTransfer();
  Array.from(files).forEach(file => dt.items.add(file));
  input.files = dt.files;
  handleReportFilesChange(input);
  toast(`${input.files.length} arquivo(s) selecionado(s) para o relatório.`);
}


function normalizeReportFileName(name) {
  const n = String(name || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (n.includes('alcance')) return 'alcance';
  if (n.includes('visualiza')) return 'visualizacoes';
  if (n.includes('intera')) return 'interacoes';
  if (n.includes('seguidor')) return 'seguidores';
  if (n.includes('visita')) return 'visitas';
  if (n.includes('clique')) return 'cliques';
  return null;
}

function readTextFileSmart(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(reader.error);
    reader.onload = () => {
      const buffer = reader.result;
      let text = new TextDecoder('utf-8').decode(buffer);
      if (text.includes('\u0000')) text = new TextDecoder('utf-16le').decode(buffer);
      resolve(text);
    };
    reader.readAsArrayBuffer(file);
  });
}

function parseCsvLine(line) {
  const out = [];
  let cur = '';
  let inside = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inside && line[i + 1] === '"') { cur += '"'; i++; }
      else inside = !inside;
    } else if ((ch === ',' || ch === ';' || ch === '\t') && !inside) {
      out.push(cur.trim());
      cur = '';
    } else {
      cur += ch;
    }
  }
  out.push(cur.trim());
  return out.map(v => v.replace(/^"|"$/g, '').trim());
}

function parseReportCsv(text) {
  const lines = String(text || '').split(/\r?\n/).map(l => l.trim()).filter(Boolean);
  const labels = [];
  const data = [];
  let total = 0;

  for (const line of lines) {
    const parts = parseCsvLine(line);
    if (parts.length < 2) continue;

    const dateRaw = (parts[0] || '').replace(/"/g, '').trim();
    if (!/^20\d{2}/.test(dateRaw)) continue;

    const valueRaw = (parts[1] || '').replace(/[^\d,-]/g, '').replace(',', '.');
    const value = Number.parseFloat(valueRaw) || 0;
    const date = dateRaw.split('T')[0];
    const d = date.split('-');
    const label = d.length === 3 ? `${d[2]}/${d[1]}` : dateRaw;

    labels.push(label);
    data.push(value);
    total += value;
  }

  return { total, labels, data };
}

async function collectReportData(clientId) {
  const client = getClients().find(c => c.id === clientId);
  const input = document.getElementById('report_files');
  const files = Array.from(input?.files || []);
  if (!client) throw new Error('Cliente não encontrado.');
  if (!files.length) throw new Error('Envie pelo menos um arquivo CSV.');

  const d = {
    cliente_nome: client.nome_cliente,
    periodo: val('report_periodo'),
    observacao: val('report_obs'),
    visualizacoes: { total: 0, labels: [], data: [] },
    alcance: { total: 0, labels: [], data: [] },
    interacoes: { total: 0, labels: [], data: [] },
    seguidores: { total: 0, labels: [], data: [] },
    visitas: { total: 0, labels: [], data: [] },
    cliques: { total: 0, labels: [], data: [] }
  };

  for (const file of files) {
    const key = normalizeReportFileName(file.name);
    if (!key) continue;
    const content = await readTextFileSmart(file);
    d[key] = parseReportCsv(content);
  }

  if (!d.periodo) {
    const labels = d.visualizacoes.labels.length ? d.visualizacoes.labels : d.alcance.labels;
    if (labels.length) {
      const yearMatch = files.map(f => f.name).join(' ').match(/20\d{2}/);
      const year = yearMatch ? yearMatch[0] : new Date().getFullYear();
      d.periodo = `${labels[0]} a ${labels[labels.length - 1]}/${year}`;
    } else {
      d.periodo = 'Período do relatório';
    }
  }

  return d;
}

function formatReportNumber(num, plus = false) {
  const n = Math.round(Number(num || 0));
  const prefix = plus && n > 0 ? '+' : '';
  if (n >= 1000) {
    const value = (n / 1000).toFixed(n >= 10000 ? 1 : 1).replace('.', ',');
    return `${prefix}${value} mil`;
  }
  return `${prefix}${n}`;
}

async function previewReportData(clientId) {
  try {
    const d = await collectReportData(clientId);
    const preview = document.getElementById('report_preview');
    preview.className = 'report-preview';
    preview.innerHTML = `
      <div class="report-kpi-mini">
        <div><small>Visualizações</small><strong>${formatReportNumber(d.visualizacoes.total)}</strong></div>
        <div><small>Alcance</small><strong>${formatReportNumber(d.alcance.total)}</strong></div>
        <div><small>Interações</small><strong>${formatReportNumber(d.interacoes.total)}</strong></div>
        <div><small>Seguidores</small><strong>${formatReportNumber(d.seguidores.total, true)}</strong></div>
        <div><small>Cliques</small><strong>${formatReportNumber(d.cliques.total)}</strong></div>
      </div>
      <p style="margin:12px 0 0;"><strong>Período:</strong> ${escapeHtml(d.periodo)}</p>
    `;
  } catch (error) {
    toast(error.message || String(error));
  }
}

function reportLineSvg(metric, color = '#4A90D9') {
  const values = metric.data || [];
  const labels = metric.labels || [];
  const w = 720, h = 220, pad = 32;
  if (!values.length) return `<div class="report-chart-empty">Sem dados suficientes para gráfico.</div>`;

  const max = Math.max(...values, 1);
  const min = 0;
  const points = values.map((v, i) => {
    const x = pad + (i * (w - pad * 2) / Math.max(values.length - 1, 1));
    const y = h - pad - ((v - min) / (max - min || 1)) * (h - pad * 2);
    return [x, y];
  });
  const line = points.map(p => p.join(',')).join(' ');
  const area = `${pad},${h-pad} ${line} ${w-pad},${h-pad}`;
  const labelStep = Math.max(1, Math.ceil(labels.length / 8));

  return `
    <svg viewBox="0 0 ${w} ${h}" class="report-chart-svg" xmlns="http://www.w3.org/2000/svg">
      ${[0,1,2,3,4].map(i => {
        const y = pad + i * ((h - pad * 2) / 4);
        return `<line x1="${pad}" x2="${w-pad}" y1="${y}" y2="${y}" stroke="#E0E8F4" stroke-width="1"/>`;
      }).join('')}
      <polygon points="${area}" fill="${color}" opacity=".12"></polygon>
      <polyline points="${line}" fill="none" stroke="${color}" stroke-width="4" stroke-linecap="round" stroke-linejoin="round"></polyline>
      ${points.map((p, i) => i % labelStep === 0 ? `<text x="${p[0]}" y="${h-8}" font-size="11" fill="#6B7A99" text-anchor="middle">${escapeHtml(labels[i] || '')}</text>` : '').join('')}
    </svg>
  `;
}


function buildReportHTML(d) {
  const generatedAt = new Date().toLocaleDateString('pt-BR');
  const logoUrl = 'data:image/png;base64,';
  return `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <title>Relatório - ${escapeHtml(d.cliente_nome)}</title>
  <script src="https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js"><\/script>
  <style>
    * { box-sizing: border-box; }
    body { margin: 0; background: #E9EEF5; color: #1A1A2E; font-family: Arial, sans-serif; padding: 24px; }
    .page { width: 1180px; margin: 0 auto; background: #fff; padding: 28px; border-radius: 22px; }
    .header { background: linear-gradient(135deg,#1B3A6B,#2A5298); color:#fff; padding:34px 36px; border-radius:22px; display:flex; justify-content:space-between; gap:24px; align-items:center; }
    .header-logo {
      max-width: 220px;
      max-height: 90px;
      width: auto;
      height: auto;
      display: block;
      object-fit: contain;
    }
    h1 { margin:0; font-size: 34px; line-height:1.1; }
    .period { opacity:.85; margin:8px 0 0; font-size: 18px; }
    .client { font-weight:800; font-size:30px; margin-top:12px; }
    .kpis { display:grid; grid-template-columns:repeat(5,1fr); gap:16px; margin:28px 0; }
    .kpi { background:#fff; border-left:5px solid #4A90D9; border-radius:16px; padding:18px 16px; box-shadow:0 8px 20px rgba(27,58,107,.08); min-height:128px; }
    .kpi small { color:#6B7A99; font-weight:700; display:block; margin-bottom:10px; font-size:16px; }
    .kpi strong { color:#1B3A6B; font-size:32px; display:block; line-height:1.08; }
    .metric-section { display:grid; grid-template-columns:240px 1fr; gap:26px; align-items:center; border-radius:18px; box-shadow:0 8px 20px rgba(27,58,107,.08); padding:24px; margin:26px 0; background:#fff; }
    .metric-left { border-right:1px solid #E0E8F4; padding-right:22px; }
    .metric-left small { color:#6B7A99; font-weight:700; display:block; margin-bottom:12px; font-size:18px; }
    .metric-left strong { color:#1B3A6B; font-size:48px; line-height:1; display:block; }
    .metric-section h2 { margin:0 0 12px; font-size:24px; color:#1A1A2E; }
    .report-chart-svg { width:100%; height:auto; display:block; background:#fff; }
    .report-chart-empty { height:220px; display:flex; align-items:center; justify-content:center; color:#6B7A99; background:#F4F7FB; border-radius:12px; }
    .obs { margin-top:24px; background:#F4F7FB; border-radius:16px; padding:18px; color:#394861; font-size:18px; }
    .footer { margin-top:24px; color:#6B7A99; font-size:13px; text-align:center; }
    .actions { position:fixed; right:24px; bottom:24px; display:flex; gap:12px; z-index:9999; }
    .actions button { padding:14px 22px; border:0; border-radius:999px; background:#1B3A6B; color:#fff; font-weight:800; cursor:pointer; box-shadow:0 10px 20px rgba(27,58,107,.24); }
    .actions button.secondary { background:#fff; color:#1B3A6B; }
    @media print { .actions { display:none; } body { background:#fff; padding:0; } .page { margin:0; width:auto; border-radius:0; } }
  </style>
</head>
<body>
  <div class="actions">
    <button class="secondary" onclick="window.print()">Imprimir</button>
    <button id="download">Baixar imagem</button>
    <button id="send">Enviar para cliente</button>
  </div>

  <main class="page" id="relatorio">
    <header class="header">
      <div>
        <img src="${logoUrl}" class="header-logo" alt="Leme">
      </div>
      <div style="text-align:right;">
        <h1>Relatório de Desempenho</h1>
        <div class="period">${escapeHtml(d.periodo)}</div>
        <div class="client">${escapeHtml(d.cliente_nome)}</div>
      </div>
    </header>

    <section class="kpis">
      <div class="kpi"><small>Visualizações</small><strong>${formatReportNumber(d.visualizacoes.total)}</strong></div>
      <div class="kpi"><small>Alcance</small><strong>${formatReportNumber(d.alcance.total)}</strong></div>
      <div class="kpi"><small>Interações</small><strong>${formatReportNumber(d.interacoes.total)}</strong></div>
      <div class="kpi"><small>Novos Seguidores</small><strong>${formatReportNumber(d.seguidores.total, true)}</strong></div>
      <div class="kpi"><small>Cliques no Link</small><strong>${formatReportNumber(d.cliques.total)}</strong></div>
    </section>

    <section class="metric-section">
      <div class="metric-left"><small>Total de Visualizações</small><strong>${formatReportNumber(d.visualizacoes.total)}</strong></div>
      <div><h2>Evolução Diária de Visualizações</h2>${reportLineSvg(d.visualizacoes, '#4A90D9')}</div>
    </section>

    <section class="metric-section">
      <div class="metric-left"><small>Total de Alcance</small><strong>${formatReportNumber(d.alcance.total)}</strong></div>
      <div><h2>Evolução Diária de Alcance</h2>${reportLineSvg(d.alcance, '#1B3A6B')}</div>
    </section>

    ${d.observacao ? `<section class="obs"><strong>Observação:</strong> ${escapeHtml(d.observacao)}</section>` : ''}

    <div class="footer">Relatório gerado em ${generatedAt}.</div>
  </main>

  <script>
    const REPORT_WEBHOOK_URL = ${JSON.stringify(getSettings().sendReportWebhook || '')};
    const REPORT_PAYLOAD_BASE = ${JSON.stringify({
      action: 'send_report_image',
      source: 'sistema_leme',
      client: {
        id: d.client_id || '',
        nome_cliente: d.cliente_nome || ''
      },
      periodo: d.periodo || '',
      observacao: d.observacao || '',
      generated_at: new Date().toISOString()
    })};

    async function waitForRender() {
      if (document.fonts && document.fonts.ready) {
        try { await document.fonts.ready; } catch (e) {}
      }
      const imgs = Array.from(document.images);
      await Promise.all(imgs.map(img => img.complete ? Promise.resolve() : new Promise(resolve => {
        img.onload = resolve;
        img.onerror = resolve;
      })));
      await new Promise(resolve => setTimeout(resolve, 300));
    }

    async function getReportCanvas() {
      await waitForRender();

      const target = document.getElementById('relatorio');
      return await html2canvas(target, {
        backgroundColor: '#ffffff',
        scale: 2,
        useCORS: true,
        logging: false,
        windowWidth: target.scrollWidth,
        windowHeight: target.scrollHeight
      });
    }

    async function baixarImagem() {
      const btn = document.getElementById('download');
      btn.textContent = 'Gerando imagem...';
      btn.disabled = true;

      const canvas = await getReportCanvas();

      const link = document.createElement('a');
      link.download = 'Relatorio_' + ('${d.cliente_nome}'.replace(/[^a-z0-9]+/gi,'_')) + '.png';
      link.href = canvas.toDataURL('image/png');
      link.click();

      btn.textContent = 'Baixar imagem';
      btn.disabled = false;
    }

    async function enviarRelatorio() {
      const btn = document.getElementById('send');
      if (!REPORT_WEBHOOK_URL) {
        alert('Cadastre o webhook "Enviar relatório ao cliente" nas configurações do sistema.');
        return;
      }

      btn.textContent = 'Enviando...';
      btn.disabled = true;

      try {
        const canvas = await getReportCanvas();
        const image_base64 = canvas.toDataURL('image/png');
        const response = await fetch(REPORT_WEBHOOK_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            ...REPORT_PAYLOAD_BASE,
            file_name: 'Relatorio_' + ('${d.cliente_nome}'.replace(/[^a-z0-9]+/gi,'_')) + '.png',
            mime_type: 'image/png',
            image_base64
          })
        });

        if (!response.ok) throw new Error('Erro no webhook');
        btn.textContent = 'Enviado';
        alert('Relatório enviado para o n8n.');
      } catch (error) {
        console.error(error);
        btn.textContent = 'Enviar para cliente';
        btn.disabled = false;
        alert('Não consegui enviar o relatório. Confira o webhook no n8n.');
      }
    }

    document.getElementById('download').addEventListener('click', baixarImagem);
    document.getElementById('send').addEventListener('click', enviarRelatorio);
    setTimeout(baixarImagem, 900);
  <\/script>
</body>
</html>`;
}

async function generateClientReportImage(clientId) {
  try {
    const d = await collectReportData(clientId);
    await previewReportData(clientId);
    const html = buildReportHTML(d);
    const win = window.open('', '_blank');
    if (!win) return toast('Permita pop-ups para gerar a imagem do relatório.');
    win.document.open();
    win.document.write(html);
    win.document.close();
    toast('Relatório aberto. O download da imagem será iniciado.');
  } catch (error) {
    toast(error.message || String(error));
  }
}


