function dragKanbanPost(event, postId) {
  postId = String(postId || '');
  if (!postId) return;

  const source = event.currentTarget;
  activeDrag = {
    type: 'kanban-post',
    id: postId,
    sourceElement: source,
    dropped: false
  };

  source.classList.add('is-dragging');
  source.dataset.dragging = 'true';

  event.dataTransfer.clearData();
  event.dataTransfer.setData('application/x-leme-kanban-post-id', postId);
  event.dataTransfer.setData('text/plain', `kanban:${postId}`);
  event.dataTransfer.effectAllowed = 'move';

  const preview = createDragPreview(source, 'Movendo demanda');
  if (preview && event.dataTransfer.setDragImage) {
    event.dataTransfer.setDragImage(preview, 24, 18);
  }

  requestAnimationFrame(() => {
    source.style.opacity = '0.35';
    source.style.transform = 'scale(0.98)';
  });
}

function allowKanbanDrop(event) {
  event.preventDefault();
  event.stopPropagation();

  if (event.dataTransfer) {
    event.dataTransfer.dropEffect = 'move';
  }

  const zone = event.currentTarget?.closest?.('.kanban-drop-zone') || event.currentTarget;
  zone?.classList?.add('drop-target-active');
}

async function dropPostOnStatus(event, status) {
  event.preventDefault();
  event.stopPropagation();

  const zone = event.currentTarget?.closest?.('.kanban-drop-zone') || event.currentTarget;
  zone?.classList?.remove('drop-target-hover', 'drop-target-active');

  let rawId =
    event.dataTransfer.getData('application/x-leme-kanban-post-id') ||
    event.dataTransfer.getData('text/plain') ||
    activeDrag.id ||
    '';

  rawId = String(rawId).replace(/^kanban:/, '');
  const postId = rawId.trim();

  if (!postId) {
    clearDragVisuals();
    toast('Não consegui identificar a demanda arrastada.');
    return;
  }

  const posts = getPosts();
  const index = posts.findIndex(item =>
    String(item.registro_id || item.id || '') === postId
  );

  if (index === -1) {
    clearDragVisuals();
    toast('Não encontrei a demanda no Kanban.');
    return;
  }

  const nextStatus = normalizeSystemStatus(status);
  const currentStatus = normalizeSystemStatus(posts[index].status);

  if (currentStatus === nextStatus) {
    clearDragVisuals();
    return;
  }

  const originalId = String(posts[index].registro_id || posts[index].id || postId);
  const movedPost = {
    ...posts[index],
    id: originalId,
    registro_id: originalId,
    status: nextStatus,
    updated_at: new Date().toISOString()
  };

  const previousPost = { ...posts[index] };

  posts[index] = movedPost;
  setPosts(posts);

  activeDrag.dropped = true;
  clearDragVisuals();

  render({ skipAutoSync: true });
  toast(`Salvando status: ${nextStatus}...`);

  const result = await maybeWebhook('updatePublication', {
    action: 'update_publication',
    source: 'sistema_leme',
    triggered_at: movedPost.updated_at,
    publicacao: movedPost
  });

  if (!result?.ok) {
    const rollbackPosts = getPosts();
    const rollbackIndex = rollbackPosts.findIndex(post =>
      String(post.registro_id || post.id || '') === originalId
    );

    if (rollbackIndex !== -1) {
      rollbackPosts[rollbackIndex] = previousPost;
      setPosts(rollbackPosts);
      render({ skipAutoSync: true });
    }

    toast('A alteração não foi salva. O status anterior foi restaurado.');
    return;
  }

  clearLocalOverride(LOCAL_OVERRIDE_KEYS.postStatuses, originalId);

  await new Promise(resolve => setTimeout(resolve, 250));
  await syncFromN8n({ silent: true, render: true });

  toast(`Status confirmado: ${nextStatus}.`);
}


function getCurrentWeekRange() {
  const today = getSaoPauloNow();
  const day = today.getDay();
  const start = new Date(today);
  start.setDate(today.getDate() - day + 1);
  const end = new Date(start);
  end.setDate(start.getDate() + 6);
  return { start: formatDate(start), end: formatDate(end) };
}

function isPostInRange(post, start, end) {
  return post.data_publicacao >= start && post.data_publicacao <= end;
}

