async function triggerApprovalWebhook(collaboratorId, clientId) {
  const collaborator = getCollaborators().find(c => c.id === collaboratorId);
  const client = getClients().find(c => c.id === clientId);

  if (!client || !collaborator) return toast('Cliente ou colaborador não encontrado.');

  const payload = {
    action: 'trigger_weekly_approval',
    source: 'sistema_leme',
    triggered_at: new Date().toISOString(),
    collaborator: {
      id: collaborator.id,
      nome: collaborator.nome,
      cargo: collaborator.cargo || ''
    },
    client: {
      id: client.id,
      nome_cliente: client.nome_cliente,
      especialidade: client.especialidade || '',
      cidade: client.cidade || '',
      instagram: client.instagram || '',
      banco_google: client.banco_google || client.drive_folder_id || '',
      drive_folder_id: client.drive_folder_id || client.banco_google || '',
      drive_folder_url: getClientDriveFolderUrl(client),
      telefone_secretaria: client.telefone_secretaria || '',
      secretaria: client.secretaria || ''
    },
    instruction: 'O n8n deve buscar as publicações deste cliente na Data Table, filtrar as publicações da próxima semana e enviar para aprovação pelo WhatsApp.'
  };

  await maybeWebhook('sendApproval', payload);

  toast(`Webhook de aprovação acionado para ${client.nome_cliente}.`);
}

async function sendAllApprovalsForCollaborator(collaboratorId) {
  const clients = getClients().filter(c => c.responsavel_id === collaboratorId);
  for (const client of clients) {
    await triggerApprovalWebhook(collaboratorId, client.id);
  }
}

