function allowEventDrop(event) {
  event.preventDefault();
  event.stopPropagation();

  if (event.dataTransfer) {
    event.dataTransfer.dropEffect = 'move';
  }

  const zone = event.currentTarget?.closest?.('.event-drop-zone') || event.currentTarget;
  zone?.classList?.add('drop-target-active');
}

function dragEvent(event, eventId) {
  eventId = String(eventId || '');
  if (!eventId) return;

  const source = event.currentTarget;
  activeDrag = {
    type: 'event',
    id: eventId,
    sourceElement: source,
    dropped: false
  };

  source.classList.add('is-dragging');
  source.dataset.dragging = 'true';

  event.dataTransfer.clearData();
  event.dataTransfer.setData('application/x-leme-event-id', eventId);
  event.dataTransfer.setData('text/plain', `event:${eventId}`);
  event.dataTransfer.effectAllowed = 'move';

  const preview = createDragPreview(source, 'Movendo compromisso');
  if (preview && event.dataTransfer.setDragImage) {
    event.dataTransfer.setDragImage(preview, 24, 18);
  }

  requestAnimationFrame(() => {
    source.style.opacity = '0.35';
    source.style.transform = 'scale(0.98)';
  });
}

async function dropEventOnDate(event, date) {
  event.preventDefault();
  event.stopPropagation();

  const target = event.currentTarget?.closest?.('.event-drop-zone') || event.currentTarget;
  target?.classList?.remove('drop-target-hover', 'drop-target-active');

  let rawId =
    event.dataTransfer.getData('application/x-leme-event-id') ||
    event.dataTransfer.getData('text/plain') ||
    activeDrag.id ||
    '';

  rawId = String(rawId).replace(/^event:/, '');
  const eventId = rawId.trim();

  if (!eventId) {
    clearDragVisuals();
    toast('Não consegui identificar o compromisso arrastado.');
    return;
  }

  const events = getEvents();
  const index = events.findIndex(item => {
    const itemId = String(item.registro_id || item.id || '');
    return itemId === eventId;
  });

  if (index === -1) {
    clearDragVisuals();
    toast('Não encontrei o compromisso na agenda.');
    return;
  }

  const oldDate = String(events[index].data || '').slice(0, 10);
  if (oldDate === date) {
    clearDragVisuals();
    return;
  }

  const originalId = String(events[index].registro_id || events[index].id || eventId);
  const hour = String(events[index].hora || '').slice(0, 5);

  const movedEvent = {
    ...events[index],
    id: originalId,
    registro_id: originalId,
    data: date,
    hora: hour,
    data_inicio: hour ? `${date}T${hour}:00` : date,
    updated_at: new Date().toISOString()
  };

  events[index] = movedEvent;
  setEvents(events);

  activeDrag.dropped = true;
  clearDragVisuals();

  // Same optimistic behavior as client calendar.
  render({ skipAutoSync: true });
  toast(`Compromisso movido para ${brDate(date)}.`);

  // Sync after UI is already updated.
  const result = await maybeWebhook('createEvent', {
    action: 'update_event',
    source: 'sistema_leme',
    triggered_at: new Date().toISOString(),
    event: {
      ...movedEvent,
      colaborador_id: movedEvent.colaborador_id || movedEvent.responsavel_id || '',
      responsavel_id: movedEvent.responsavel_id || movedEvent.colaborador_id || ''
    }
  });

  if (result?.ok === false) {
    toast('O compromisso foi movido no sistema, mas o n8n ainda não confirmou.');
    return;
  }

  // O n8n passa a ser a fonte oficial imediatamente.
  clearLocalOverride(LOCAL_OVERRIDE_KEYS.eventMoves, originalId);
  setTimeout(() => syncFromN8n({ silent: true, render: true }), 250);
}


