function getSystemDataSnapshot() {
  return {
    exported_at: new Date().toISOString(),
    clients: getClients(),
    collaborators: getCollaborators(),
    posts: getPosts(),
    events: getEvents(),
    settings: getSettings()
  };
}

function downloadSystemData() {
  const data = getSystemDataSnapshot();
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `leme-flow-dados-${getSaoPauloDateKey()}.json`;
  link.click();
  URL.revokeObjectURL(url);
  toast('Dados do sistema exportados em JSON.');
}

