function closeModal() {
  state.modal = null;
  render();
  setTimeout(runPendingRealtimeSync, 120);
}

let modalBackdropSaveInProgress = false;
let modalPointerState = {
  startedInside: false,
  moved: false,
  startX: 0,
  startY: 0,
  suppressBackdropClickUntil: 0
};

function autoGrowTextarea(element) {
  if (!element) return;
  element.style.height = 'auto';
  element.style.height = `${element.scrollHeight}px`;
}

function initAutoGrowTextareas() {
  document
    .querySelectorAll('.post-title-textarea')
    .forEach(autoGrowTextarea);
}

function hasActiveTextSelection() {
  const selection = window.getSelection?.();
  return !!selection && String(selection.toString() || '').length > 0;
}

function resetModalPointerState() {
  modalPointerState.startedInside = false;
  modalPointerState.moved = false;
  modalPointerState.startX = 0;
  modalPointerState.startY = 0;
}

function handleModalPointerDown(event) {
  if (!state.modal) return;
  if (!event.target?.closest?.('.modal-backdrop')) return;

  modalPointerState.startedInside = !!event.target.closest('.modal');
  modalPointerState.moved = false;
  modalPointerState.startX = event.clientX || 0;
  modalPointerState.startY = event.clientY || 0;
}

function handleModalPointerMove(event) {
  if (!state.modal) return;
  if (!modalPointerState.startedInside) return;

  const dx = Math.abs((event.clientX || 0) - modalPointerState.startX);
  const dy = Math.abs((event.clientY || 0) - modalPointerState.startY);

  if (dx > 6 || dy > 6) {
    modalPointerState.moved = true;
  }
}

function handleModalPointerUp() {
  if (!state.modal) return;

  if (modalPointerState.startedInside || modalPointerState.moved || hasActiveTextSelection()) {
    modalPointerState.suppressBackdropClickUntil = Date.now() + 250;
  }

  setTimeout(resetModalPointerState, 260);
}

async function handleModalBackdropClick(event) {
  if (event.target !== event.currentTarget) return;
  if (modalBackdropSaveInProgress) return;

  const shouldIgnoreBackdropClick =
    modalPointerState.startedInside ||
    modalPointerState.moved ||
    Date.now() < modalPointerState.suppressBackdropClickUntil ||
    hasActiveTextSelection();

  if (shouldIgnoreBackdropClick) {
    resetModalPointerState();
    return;
  }

  const modal = state.modal;

  if (!modal) return;

  if (modal.type === 'post' && modal.postId) {
    modalBackdropSaveInProgress = true;

    try {
      await updatePost(modal.postId);
    } finally {
      modalBackdropSaveInProgress = false;
    }

    return;
  }

  if (modal.type === 'event' && modal.eventId) {
    modalBackdropSaveInProgress = true;

    try {
      await updateEvent(modal.eventId);
    } finally {
      modalBackdropSaveInProgress = false;
    }

    return;
  }

  // Publicação ou compromisso novos continuam sendo cancelados.
  // Cliente e colaborador também apenas fecham.
  closeModal();
}

function renderModal() {
  if (!state.modal) return '';
  if (state.modal.type === 'client') return renderClientModal();
  if (state.modal.type === 'post') return renderPostModal();
  if (state.modal.type === 'event') return renderEventModal();
  if (state.modal.type === 'collaborator') return renderCollaboratorModal();
  if (String(state.modal.type || '').startsWith('crm-') && typeof window.crmRenderModal === 'function') return window.crmRenderModal();
  return '';
}

