function syncResponsibleFromClient() {
  const clientId = val('p_cliente_id');
  const client = getClients().find(c => c.id === clientId);
  if (client) document.getElementById('p_responsavel_id').value = client.responsavel_id || '';
}
function collectPost() {
  return { cliente_id: val('p_cliente_id'), titulo: val('p_titulo'), tema: val('p_tema'), formato: val('p_formato'), data_publicacao: val('p_data_publicacao'), status: val('p_status'), responsavel_id: val('p_responsavel_id'), texto_carrossel: val('p_texto_carrossel'), observacoes: val('p_observacoes'), drive_folder_url: val('p_drive_folder_url'), };
}
async function createPost() {
  const data = collectPost();

  if (!data.cliente_id) return toast('Selecione um cliente.');
  if (!data.titulo) return toast('Informe o título da publicação.');

  const id = uid();
  const now = new Date().toISOString();

  const post = {
    id,
    registro_id: id,
    ...data,
    created_at: now,
    updated_at: now
  };

  const posts = getPosts();
  posts.push(post);
  setPosts(posts);

  toast('Criando publicação...');

  const result = await maybeWebhook('createPublication', {
    action: 'create_publication',
    source: 'sistema_leme',
    triggered_at: now,
    publicacao: post
  });

  if (!result?.ok) {
    setPosts(getPosts().filter(item =>
      String(item.registro_id || item.id || '') !== id
    ));

    toast('A publicação não foi criada porque o n8n não confirmou.');
    render({ skipAutoSync: true });
    return;
  }

  closeModal();

  await new Promise(resolve => setTimeout(resolve, 250));
  await syncFromN8n({ silent: true, render: true });

  toast('Publicação criada e confirmada.');
}
async function updatePost(id) {
  const posts = getPosts();
  const index = posts.findIndex(post =>
    String(post.registro_id || post.id || '') === String(id)
  );

  if (index === -1) return;

  const previousPost = { ...posts[index] };
  const canonicalId = String(
    previousPost.registro_id ||
    previousPost.id ||
    id
  );

  const updatedPost = {
    ...previousPost,
    ...collectPost(),
    id: canonicalId,
    registro_id: canonicalId,
    updated_at: new Date().toISOString()
  };

  posts[index] = updatedPost;
  setPosts(posts);

  toast('Salvando publicação...');

  const result = await maybeWebhook('updatePublication', {
    action: 'update_publication',
    source: 'sistema_leme',
    triggered_at: updatedPost.updated_at,
    publicacao: updatedPost
  });

  if (!result?.ok) {
    const rollbackPosts = getPosts();
    const rollbackIndex = rollbackPosts.findIndex(post =>
      String(post.registro_id || post.id || '') === canonicalId
    );

    if (rollbackIndex !== -1) {
      rollbackPosts[rollbackIndex] = previousPost;
      setPosts(rollbackPosts);
    }

    toast('A edição não foi salva. Os dados anteriores foram restaurados.');
    render({ skipAutoSync: true });
    return;
  }

  closeModal();

  await new Promise(resolve => setTimeout(resolve, 250));
  await syncFromN8n({ silent: true, render: true });

  toast('Publicação atualizada e confirmada.');
}
async function deletePost(id) {
  const canonicalId = String(id || '');

  const posts = getPosts();
  const post = posts.find(item =>
    String(item.registro_id || item.id || '') === canonicalId
  );

  if (!post) {
    toast('Publicação não encontrada.');
    return;
  }

  const confirmed = window.confirm(
    `Deseja realmente excluir a publicação "${post.titulo || 'sem título'}"?`
  );

  if (!confirmed) return;

  const deleteButton = document.querySelector('.modal .btn.danger');

  if (deleteButton) {
    deleteButton.disabled = true;
    deleteButton.textContent = 'Excluindo...';
  }

  const result = await maybeWebhook('deletePublication', {
    action: 'delete_publication',
    source: 'sistema_leme',
    triggered_at: new Date().toISOString(),
    registro_id: canonicalId,
    publicacao: {
      ...post,
      id: canonicalId,
      registro_id: canonicalId
    }
  });

  if (!result?.ok) {
    if (deleteButton) {
      deleteButton.disabled = false;
      deleteButton.textContent = 'Excluir';
    }

    toast('A publicação não foi excluída porque o n8n não confirmou.');
    return;
  }

  const remainingPosts = getPosts().filter(item =>
    String(item.registro_id || item.id || '') !== canonicalId
  );

  setPosts(remainingPosts);
  clearLocalOverride(LOCAL_OVERRIDE_KEYS.postStatuses, canonicalId);
  closeModal();

  await new Promise(resolve => setTimeout(resolve, 250));
  await syncFromN8n({
    silent: true,
    render: true
  });

  toast('Publicação excluída definitivamente.');
}

async function deleteSelectedCalendarPosts() {
  const ids = getSelectedCalendarPostIds();

  if (!ids.length) {
    state.postContextMenu = null;
    render({ skipAutoSync: true });
    return;
  }

  const posts = getPosts();
  const selectedPosts = posts.filter(post => ids.includes(String(post.registro_id || post.id || '')));

  if (!selectedPosts.length) {
    clearCalendarPostSelection();
    render({ skipAutoSync: true });
    toast('Nenhuma publicação selecionada foi encontrada.');
    return;
  }

  const confirmed = window.confirm(
    selectedPosts.length === 1
      ? `Deseja realmente excluir a publicação "${selectedPosts[0].titulo || 'sem título'}"?`
      : `Deseja realmente excluir ${selectedPosts.length} publicações selecionadas?`
  );

  if (!confirmed) return;

  state.postContextMenu = null;
  render({ skipAutoSync: true });

  const registroIds = selectedPosts.map(post => String(post.registro_id || post.id || '')).filter(Boolean);

  const result = await maybeWebhook('deletePublications', {
    action: 'delete_publications',
    source: 'sistema_leme',
    triggered_at: new Date().toISOString(),
    registro_ids: registroIds,
    publicacoes: selectedPosts.map(post => ({
      ...post,
      id: String(post.registro_id || post.id || ''),
      registro_id: String(post.registro_id || post.id || '')
    }))
  });

  if (!result?.ok) {
    toast(result?.error || 'As publicações não foram excluídas porque a API não confirmou.');
    return;
  }

  const deleteSet = new Set(registroIds);
  setPosts(getPosts().filter(post => !deleteSet.has(String(post.registro_id || post.id || ''))));
  registroIds.forEach(id => clearLocalOverride(LOCAL_OVERRIDE_KEYS.postStatuses, id));
  clearCalendarPostSelection();

  await new Promise(resolve => setTimeout(resolve, 250));
  await syncFromN8n({ silent: true, render: true });

  toast(selectedPosts.length === 1 ? 'Publicação excluída.' : `${selectedPosts.length} publicações excluídas.`);
}

async function createDriveForPost(id) {
  if (!id) return toast('Salve a demanda antes de acionar o n8n para criar a pasta.');
  const posts = getPosts(); const post = posts.find(p => p.id === id); if (!post) return;
  const client = getClients().find(c => c.id === post.cliente_id);
  const res = await maybeWebhook('driveAutomation', { post, client });
  if (res?.banco_google) post.drive_folder_url = res.banco_google;
  post.updated_at = new Date().toISOString();
  setPosts(posts); toast(post.drive_folder_url ? 'Pasta criada e vinculada.' : 'Solicitação enviada ao n8n.'); render();
}

